scwin.memJson = $c.data.getMemInfo($p);
scwin.loUpperLobranCd = $c.data.getMemInfo($p, "loUpperLobranCd"); //상위물류점소코드
scwin.loUpperLobranNm = $c.data.getMemInfo($p, "loUpperLobranNm"); //상위물류점소

