scwin.onpageload = function () {
  //차량보험료 청구/회수 현황 화면  파라미터
  scwin.params = $c.data.getParameter($p);
  ed_stdDt.setValue(scwin.strYm); // 초기값 셋팅

  scwin.drcrNo = scwin.params.drcrNo;
  scwin.stdDt = scwin.params.stdDt;
  scwin.lobranCd = scwin.params.lobranCd;

  //------------------------------------------------------------
  // 파라미터에 의한 오프레이션
  //------------------------------------------------------------
  if (!$c.gus.cfIsNull($p, scwin.drcrNo)) {
    ed_drcrNo.setValue(scwin.drcrNo);
  }
  if (!$c.gus.cfIsNull($p, scwin.stdDt)) {
    ed_stdDt.setValue(scwin.stdDt);
  }
  if (!$c.gus.cfIsNull($p, scwin.lobranCd)) {
    lc_lobranCd.setValue(scwin.lobranCd);
  }
  if (!$c.gus.cfIsNull($p, scwin.drcrNo) || !$c.gus.cfIsNull($p, scwin.stdDt) || !$c.gus.cfIsNull($p, scwin.lobranCd)) {
    scwin.btn_retrieve_onclick();
  }
  scwin.onloadComplete();
};
scwin.onloadComplete = function () {
  /*소속지사 setting*/
  sbm_lobran.action = "/ds.co.RetreiveLoBranCMD.do";
  $c.sbm.execute($p, sbm_lobran);

  /*grid 담보 setting*/
  sbm_pldg.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=FS151";
  $c.sbm.execute($p, sbm_pldg);

  //공통코드
  const codeOptions = [{
    grpCd: "ZZ203",
    compID: "lc_posnClsCd"
  },
  //차량구분
  {
    grpCd: "ZZ102",
    compID: "gr_insr:insrCoCd"
  },
  //보험사
  {
    grpCd: "FS150",
    compID: "gr_insr:insrCd,gr_except:insrCd"
  },
  //보험
  {
    grpCd: "FS153",
    compID: "gr_insr:completeCd"
  },
  //완료구분
  {
    grpCd: "FS152",
    compID: "gr_insr:compCd"
  } //배상구분
  ];
  $c.data.setCommonCode($p, codeOptions);
};

// 점소 콤보(소속 지사)
scwin.sbm_lobran_submitdone = function () {
  //소속지사 세팅
  lc_lobranCd.setValue(scwin.loUpperLobranCd);
  lc_lobranCd.focus();
};

//============================
//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_OpenPopup = async function (disGubun, pCode, pName, pClose) {
  switch (disGubun) {
    // 협력업체 팝업
    case 1:
      udc_comCode_clnt.setSelectId("retrieveCarKindClntInfo");
      await udc_comCode_clnt.cfCommonPopUp(scwin.udc_comCode_clnt_callBackFunc, pCode, pName, pClose, null, null, null, null, null, null, null, null, null);
      break;

    // 차량팝업 (장비)
    case 2:
      udc_comCode_eq.setSelectId("retrieveKndVehclListInfo");
      await udc_comCode_eq.cfCommonPopUp(scwin.udc_comCode_eq_callBackFunc, pCode, pName, pClose, null, null, null, null, "LO", null, null, null, null);
      break;
    default:
      console.warn("f_OpenPopup: 정의되지 않은 disGubun ->", disGubun);
      break;
  }
};

/* ------------------------------------------------------------------ */
/*  scwin 이벤트 바인딩                                                  */
/* ------------------------------------------------------------------ */
// 차량(장비)
scwin.udc_comCode_eq_onclickEvent = function (e) {
  scwin.f_OpenPopup(2, ed_eqCd.getValue(), ed_eqNm.getValue(), "T");
};
scwin.udc_comCode_eq_onblurCodeEvent = function (e) {
  if (ed_eqCd.getValue() === "") {
    ed_eqNm.setValue("");
  } else {
    scwin.f_OpenPopup(2, ed_eqCd.getValue(), ed_eqNm.getValue(), "T");
  }
};
scwin.udc_comCode_eq_onviewchangeNameEvent = function (info) {
  if (ed_eqNm.getValue() === "") ed_eqCd.setValue("");
};

// 협력업체
scwin.udc_comCode_clnt_onclickEvent = function (e) {
  scwin.f_OpenPopup(1, ed_clntNo.getValue(), ed_clntNm.getValue(), "T");
};
scwin.udc_comCode_clnt_onblurCodeEvent = function (e) {
  if (ed_clntNo.getValue() === "") {
    ed_clntNm.setValue("");
  } else {
    scwin.f_OpenPopup(1, ed_clntNo.getValue(), ed_clntNm.getValue(), "T");
  }
};
scwin.udc_comCode_clnt_onviewchangeNameEvent = function (info) {
  if (ed_clntNm.getValue() === "") ed_clntNo.setValue("");
};

//차량pop callbaack
scwin.udc_comCode_eq_callBackFunc = function (rtnList) {
  $c.gus.cfSetReturnValue($p, rtnList, ed_eqCd, ed_eqNm);
};
//협력업체 pop callback
scwin.udc_comCode_clnt_callBackFunc = function (rtnList) {
  $c.gus.cfSetReturnValue($p, rtnList, ed_clntNo, ed_clntNm);
};

//장비리스트조회 조회
scwin.btn_retrieve_onclick = function (e) {
  //dataMap set..
  dma_queryCondition.set("stdDt", ed_stdDt.getValue());
  dma_queryCondition.set("lobranCd", lc_lobranCd.getValue());
  dma_queryCondition.set("posnClsCd", lc_posnClsCd.getValue());
  dma_queryCondition.set("eqCd", ed_eqCd.getValue());
  dma_queryCondition.set("drcrNo", ed_drcrNo.getValue());
  dma_queryCondition.set("clntNo", ed_clntNo.getValue());
  $c.sbm.execute($p, sbm_retrieve);
};

//장비리스트조회 조회callback
scwin.sbm_retrieve_submitdone = function () {
  let nCnt = ds_carInfo.getRowCount();
  if (nCnt == 0) {
    return;
  } else {
    gr_carInfo.setFocusedCell(0, 0);
    total.setValue(nCnt);
    scwin.f_retrieve2();
  }
};

//장비리스트조회 grid Click event
scwin.gr_carInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
  scwin.f_retrieve2();
};

//장비보험조회/차량보험료조회
scwin.f_retrieve2 = function () {
  dma_queryCondition2.set("stdDt", ed_stdDt.getValue());
  dma_queryCondition2.set("drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));
  $c.sbm.execute($p, sbm_retrieve2); //tab1 (장비보험조회)
  $c.sbm.execute($p, sbm_retrieve3); //tab2 (차량보험료조회)
};

//장비보험조회 callback
