//-------------------------------------------------------------------------
//  그리드추가 - 코드 적용
//-------------------------------------------------------------------------
scwin.f_addRow = function (data) {
  // I: 보험추가, S: 특약추가
  switch (data) {
    case 'I':
      if ($c.util.isEmpty($p, ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"))) {
        $c.win.alert($p, "차량보험료 등록 시 차대번호는 필수입니다." + "\n공통-장비-장비관리에서 차대번호를 입력해주세요.");
        return;
      } else {
        let rowIndex = ds_insr.getRowCount();
        ds_insr.insertRow(rowIndex);
        gr_insr.setFocusedCell(rowIndex, 0);
        ds_insr.setCellData(rowIndex, "insrNo", "");
        ds_insr.setCellData(rowIndex, "pldgSeq", "");
        ds_insr.setCellData(rowIndex, "drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));
        ds_insr.setCellData(rowIndex, "insrCoCd", "DB");
        ds_insr.setCellData(rowIndex, "insrCd", "");
        ds_insr.setCellData(rowIndex, "pldgCd", "");
        ds_insr.setCellData(rowIndex, "insrStDt", "");
        ds_insr.setCellData(rowIndex, "insrEndDt", "");
        ds_insr.setCellData(rowIndex, "adptDays", 0);
        ds_insr.setCellData(rowIndex, "psnlAmt1", 0);
        ds_insr.setCellData(rowIndex, "psnlAmt2", 0);
        ds_insr.setCellData(rowIndex, "impsnlAmt", 0);
        ds_insr.setCellData(rowIndex, "insrAmt", 0);
        ds_insr.setCellData(rowIndex, "completeCd", "01");
        ds_insr.setCellData(rowIndex, "estTmnDt", "");
        ds_insr.setCellData(rowIndex, "dcsnTmnDt", "");
        ds_insr.setCellData(rowIndex, "tmnRefundAmt", 0);
        ds_insr.setCellData(rowIndex, "compCd", "");
        ds_insr.setCellData(rowIndex, "evidFilePath", "");
        ds_insr.setCellData(rowIndex, "calcFilePath", "");
        ds_insr.setCellData(rowIndex, "eqCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "eqCd"));
        ds_insr.setCellData(rowIndex, "lobranCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "lobranCd"));
        ds_insr.setCellData(rowIndex, "posnClsCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "posnClsCd"));
        ds_insr.setCellData(rowIndex, "mainYn", 1);
        scwin.addOption = 0;
      }
      break;
    case 'S':
      if (ds_insr.getRowCount() == 0) {
        $c.win.alert($p, "특약추가는 보험 조회 후 가능합니다.");
        return;
      } else {
        let j = 0;

        // 1. 체크 + mainYn == 1 인 행 카운트
        for (var i = 0; i < ds_insr.getRowCount(); i++) {
          if (ds_insr.getCellData(i, "chk") == "T" && ds_insr.getCellData(i, "mainYn") == 1) {
            j++;
          }
        }

        // 1개가 아니면 경고 후 체크 전부 해제
        if (j < 1 || j > 1) {
          $c.win.alert($p, "특약을 추가할 보험을 선택 후 특약추가 버튼을 클릭하세요");
          for (var i = 0; i < ds_insr.getRowCount(); i++) {
            if (ds_insr.getCellData(i, "chk") == "T") {
              ds_insr.setCellData(i, "chk", "F");
            }
          }
          return;
        } else {
          let row = 0;
          for (var i = 0; i < ds_insr.getRowCount(); i++) {
            if (ds_insr.getCellData(i, "chk") == "T" && ds_insr.getCellData(i, "mainYn") == 1) {
              row = i;
            }
          }
          if (ds_insr.getCellData(row, "mainYn") != 1) {
            $c.win.alert($p, "특약을 추가할 보험을 선택 후 특약추가 버튼을 클릭하세요.");
            return;
          }
          if (ds_insr.getCellData(row, "completeCd") != "01") {
            $c.win.alert($p, "갱신, 해지된 보험에는 특약을 추가할 수 없습니다.");
            return;
          }
          if (ds_insr.getCellData(row, "insrCd") == "") {
            $c.win.alert($p, "보험 선택 후 특약을 추가해 주세요.");
            gr_insr.setFocusCell("insrCd");
            gr_insr.focus();
            return;
          }
          let rowIndex = ds_insr.getRowCount();
          ds_insr.insertRow(rowIndex);
          gr_insr.setFocusedCell(rowIndex, 0);
          ds_insr.setCellData(rowIndex, "insrNo", ds_insr.getCellData(row, "insrNo"));
          ds_insr.setCellData(rowIndex, "pldgSeq", "");
          ds_insr.setCellData(rowIndex, "drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));
          ds_insr.setCellData(rowIndex, "insrCoCd", "DB");
          ds_insr.setCellData(rowIndex, "insrCd", ds_insr.getCellData(row, "insrCd"));
          ds_insr.setCellData(rowIndex, "pldgCd", "");
          ds_insr.setCellData(rowIndex, "insrStDt", ds_insr.getCellData(row, "insrStDt"));
          ds_insr.setCellData(rowIndex, "insrEndDt", ds_insr.getCellData(row, "insrEndDt"));
          ds_insr.setCellData(rowIndex, "adptDays", 0);
          ds_insr.setCellData(rowIndex, "psnlAmt1", 0);
          ds_insr.setCellData(rowIndex, "psnlAmt2", 0);
          ds_insr.setCellData(rowIndex, "impsnlAmt", 0);
          ds_insr.setCellData(rowIndex, "insrAmt", 0);
          ds_insr.setCellData(rowIndex, "completeCd", "01");
          ds_insr.setCellData(rowIndex, "estTmnDt", "");
          ds_insr.setCellData(rowIndex, "dcsnTmnDt", "");
          ds_insr.setCellData(rowIndex, "tmnRefundAmt", 0);
          ds_insr.setCellData(rowIndex, "compCd", "");
          ds_insr.setCellData(rowIndex, "evidFilePath", "");
          ds_insr.setCellData(rowIndex, "calcFilePath", "");
          ds_insr.setCellData(rowIndex, "eqCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "eqCd"));
          ds_insr.setCellData(rowIndex, "lobranCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "lobranCd"));
          ds_insr.setCellData(rowIndex, "posnClsCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "posnClsCd"));
          ds_insr.setCellData(rowIndex, "mainYn", 0);
          ds_insr.setCellData(row, "chk", "F");
          scwin.addOption = 1;
        }
      }
      break;

    // 청구제외 그리드 행추가
    case 'E':
      let rowIndex = ds_except.getRowCount();
      ds_except.insertRow(rowIndex);
      gr_except.setFocusedCell(rowIndex, 0);
      ds_except.setCellData(rowIndex, "insrNo", ds_insr.getCellData(ds_insr.getRowPosition(), "insrNo"));
      ds_except.setCellData(rowIndex, "insrCd", ds_insr.getCellData(ds_insr.getRowPosition(), "insrCd"));
      ds_except.setCellData(rowIndex, "exceptStDt", "");
      ds_except.setCellData(rowIndex, "exceptEndDt", "");
      ds_except.setCellData(rowIndex, "adptDays", 0);
      ds_except.setCellData(rowIndex, "exceptRsn", "");
      break;
  }
};

//파일 다운로드
scwin.resultDown_onclick = function (e) {
  let row = ds_insr.getRowPosition();
  let col = gr_insr.getColumnID();
  if (row < 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["첨부파일 행"]);
    return;
  } else {
    let fileName = "";
    let filePath = "";
    if (col == "evidFileNm") {
      fileName = ds_insr.getCellData(row, "evidFileNm");
      filePath = ds_insr.getCellData(row, "evidFilePath");
    } else if (col == "calcFileNm") {
      fileName = ds_insr.getCellData(row, "calcFileNm");
      filePath = ds_insr.getCellData(row, "calcFilePath");
    }
    if (filePath.trim().length == 0) {
      $c.win.alert($p, "선택하신 " + (row + 1) + "행에 파일이 등록되어 있지 않습니다.");
    } else {
      if (filePath.indexOf(".") > 0) {
        fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".") + 4);
        $c.gus.cfDownloadFile($p, fileName, filePath);
      }
    }
  }
};

//grid (gr_insr) focus kill event
scwin.gr_insr_onafteredit = function (rowIndex, columnIndex, value) {
  // 보험료 합계 로직. AS_IS 에서 동작 안하는데.
  let colid = gr_insr.getColumnID(columnIndex);
  switch (colid) {
    case "psnlAmt1":
    case "psnlAmt2":
    case "impsnlAmt":
      // parseInt 또는 parseFloat으로 숫자 변환 후 합산
      var psnlAmt1 = parseInt(ds_insr.getCellData(rowIndex, "psnlAmt1") || 0, 10);
      var psnlAmt2 = parseInt(ds_insr.getCellData(rowIndex, "psnlAmt2") || 0, 10);
      var impsnlAmt = parseInt(ds_insr.getCellData(rowIndex, "impsnlAmt") || 0, 10);
      ds_insr.setCellData(rowIndex, "insrAmt", psnlAmt1 + psnlAmt2 + impsnlAmt);
      break;
    case "pldgCd":
      // filter를 초기화하지 않을 경우, 기존 다른 row의 pldgCd 값에도 영향을 주어 값이 초기화될 수 있음
      ds_pldg.clearFilter();
      break;
  }
};

//컬럼 옮기게 할지 말지 처리.
scwin.gr_insr_onbeforecolumnmove = function (info) {
  switch (info.startColumnID) {
    case "chk":
    case "insrCoCd":
    case "insrCd":
    case "pldgCd":
      return false;
  }
  return true;
};

//차량보험료 등록 저장 (f_Save1)
scwin.btn_save_onclick = async function (e) {
  if (ds_insr.getRowCount() == 0) {
    $c.win.alert($p, "저장할 차량보험료 내역이 없습니다.");
    return;
  }
  for (var i = 0; i < ds_insr.getRowCount(); i++) {
    if (!$c.gus.cfIsAfterDate($p, ds_insr.getCellData(i, "insrStDt").trim(), ds_insr.getCellData(i, "insrEndDt").trim())) {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
      return;
    }
    if (ds_insr.getRowStatusValue(i) == 2) {
      //신규

      if (ds_insr.getCellData(i, "insrCd") == "01" && (ds_insr.getCellData(i, "pldgCd") == "01" || ds_insr.getCellData(i, "pldgCd") == "02")) {
        if (ds_insr.getCellData(i, "psnlAmt1") > 0 || ds_insr.getCellData(i, "psnlAmt2") > 0 || ds_insr.getCellData(i, "impsnlAmt") > 0) {
          // parseInt 또는 parseFloat으로 숫자 변환 후 합산
          var psnlAmt1 = parseInt(ds_insr.getCellData(i, "psnlAmt1") || 0, 10);
          var psnlAmt2 = parseInt(ds_insr.getCellData(i, "psnlAmt2") || 0, 10);
          var impsnlAmt = parseInt(ds_insr.getCellData(i, "impsnlAmt") || 0, 10);
          ds_insr.setCellData(i, "insrAmt", psnlAmt1 + psnlAmt2 + impsnlAmt);
        }
      }
      if (ds_insr.getCellData(i, "compCd") != "") {
        if (ds_insr.getCellData(i, "insrCd") != "01" || ds_insr.getCellData(i, "pldgCd") != "01" && ds_insr.getCellData(i, "pldgCd") != "02") {
          $c.win.alert($p, "배상구분은 자동차보험(단기,일반)의 해지인 경우에 입력합니다.");
          ds_insr.setCellData(i, "compCd", "");
          return;
        }
      }
    }
  }

  //필수Validate
  if (await $c.gus.cfValidate($p, [gr_insr])) {
    let confirm = await $c.win.confirm($p, "저장하시겠습니까?");
    if (confirm) {
      $c.sbm.execute($p, sbm_save);
    }
  }
};
scwin.sbm_save_submitdone = async function (e) {
  // responseJSON에서 resultDataSet 추출
  var resultDataSet = e.responseJSON.resultDataSet;
  if (!resultDataSet || resultDataSet.length === 0) {
    return;
  }

  // 첫번째 행 = Result (성공/실패 여부)
  var result = resultDataSet[0];
  if (result.Msg === "SUCC") {
    // 성공
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.f_retrieve2();
  }
};

